  var BODY_HTML = "\n\n<!-- ============ HERO ============ -->\n<header class=\"hero\" id=\"hero\">\n  <div class=\"wrap\">\n    <div class=\"hero-copy reveal\">\n      <h1>\n        <span class=\"accent\">Ventura 150R</span><br/>\n        Make fresh water,<br/>\n        anywhere you cruise.\n      </h1>\n      <p class=\"lede\">\n        Spectra's most popular DC watermaker — <strong>6.3 gallons per hour</strong>\n        of clean, drinkable water from a compact, modular system that runs on\n        battery, solar, or wind. Quiet enough to run overnight. Sized to fit\n        boats from 30 to 50 ft.\n      </p>\n\n      <div class=\"hero-stats\">\n        <div class=\"stat\">\n          <div class=\"n\">6.3<span class=\"u\">GPH</span></div>\n          <div class=\"l\">Production</div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"n\">12 / 24<span class=\"u\">V DC</span></div>\n          <div class=\"l\">Voltage</div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"n\">60<span class=\"u\">lbs</span></div>\n          <div class=\"l\">Weight</div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"n\">ER</div>\n          <div class=\"l\">Clark Pump</div>\n        </div>\n      </div>\n\n      <div class=\"cta-row\">\n        <a class=\"btn btn-primary btn-lg\" href=\"https://sealiferfq.paperform.co/\" target=\"_blank\" rel=\"noopener\">\n          Request a Quote\n          <span class=\"arrow\" aria-hidden=\"true\">→</span>\n        </a>\n        <a class=\"btn btn-light btn-lg\" href=\"#specs\">Full specifications</a>\n        <span class=\"cta-note\">Sales · Install · Service in Tampa Bay, FL</span>\n      </div>\n    </div>\n\n    <div class=\"hero-visual reveal\">\n      <span class=\"hero-corner-tag\">VT-150R-12</span>\n      <img src=\"https://spectrawatermakers.com/cdn/shop/files/IMG_Spectrawatermakers_Ventura_150R.png?v=1742998667&width=1200\" alt=\"Spectra Ventura 150R watermaker — modular DC reverse osmosis system\" />\n      <div class=\"hero-spectra-tag\">\n        <img src=\"https://spectrawatermakers.com/cdn/shop/files/Spectra_Watermakers_Logo_Horizontal_RGB.png?v=1742380991&width=400\" alt=\"Spectra Watermakers\" />\n        <span>Authorized Dealer</span>\n      </div>\n    </div>\n  </div>\n</header>\n\n<!-- ============ TRUST BAR ============ -->\n<div class=\"trust\">\n  <div class=\"wrap\">\n    <span class=\"trust-label\">SeaLife Marine is</span>\n    <div class=\"trust-items\">\n      <span class=\"trust-item\">NMEA Certified</span>\n      <span class=\"trust-item\">NMEA 2000 Certified</span>\n      <span class=\"trust-item\">ABYC Certified</span>\n      <span class=\"trust-item\">Authorized Spectra Dealer</span>\n      <span class=\"trust-item\">40+ Years Experience</span>\n    </div>\n  </div>\n</div>\n\n<!-- ============ VENTURA SERIES ============ -->\n<section class=\"series\" id=\"series\">\n  <div class=\"wrap\">\n    <div class=\"section-head reveal\">\n      <div>\n        <div class=\"eyebrow\">Ventura Series</div>\n        <h2>The 150R is one of six. Here's the full lineup.</h2>\n      </div>\n      <p class=\"subtitle\">SeaLife Marine sells, installs, and services every model in Spectra's Marine Ventura Series. Not sure which is right for your boat? We'll help you size it.</p>\n    </div>\n\n    <div class=\"series-grid reveal\" id=\"seriesGrid\">\n\n      <button type=\"button\" class=\"series-card is-active\" data-model=\"150R\" aria-pressed=\"true\">\n        <div class=\"series-img\">\n          <span class=\"series-tag\">Featured</span>\n          <img src=\"https://spectrawatermakers.com/cdn/shop/files/IMG_Spectrawatermakers_Ventura_150R.png?v=1742998667&width=900\" alt=\"Ventura 150R\" loading=\"lazy\" />\n        </div>\n        <div class=\"series-body\">\n          <h3>Ventura 150R</h3>\n          <p class=\"series-desc\">Energy-efficient, lightweight, compact. 6.3 GPH with the Spectra Remote Manual.</p>\n          <div class=\"series-stats\">\n            <span class=\"ss\"><b>12/24V</b><i>Voltage</i></span>\n            <span class=\"ss\"><b>6.3 GPH</b><i>Output</i></span>\n            <span class=\"ss\"><b>60 lbs</b><i>Weight</i></span>\n            <span class=\"ss\"><b>No</b><i>MFD</i></span>\n          </div>\n        </div>\n      </button>\n\n      <button type=\"button\" class=\"series-card\" data-model=\"150C\" aria-pressed=\"false\">\n        <div class=\"series-img\">\n          <img src=\"https://spectrawatermakers.com/cdn/shop/files/IMG_Spectrawatermakers_Ventura_150C.png?v=1742998670&width=900\" alt=\"Ventura 150C\" loading=\"lazy\" />\n        </div>\n        <div class=\"series-body\">\n          <h3>Ventura 150C</h3>\n          <p class=\"series-desc\">6+ GPH for smaller vessels. Remote operation and advanced modes via Spectra Connect.</p>\n          <div class=\"series-stats\">\n            <span class=\"ss\"><b>12/24V</b><i>Voltage</i></span>\n            <span class=\"ss\"><b>6+ GPH</b><i>Output</i></span>\n            <span class=\"ss\"><b>85 lbs</b><i>Weight</i></span>\n            <span class=\"ss\"><b>Yes</b><i>MFD</i></span>\n          </div>\n        </div>\n      </button>\n\n      <button type=\"button\" class=\"series-card\" data-model=\"150D\" aria-pressed=\"false\">\n        <div class=\"series-img\">\n          <img src=\"https://spectrawatermakers.com/cdn/shop/files/IMG_Spectrawatermakers_Ventura_150.png?v=1742998669&width=900\" alt=\"Ventura 150D\" loading=\"lazy\" />\n        </div>\n        <div class=\"series-body\">\n          <h3>Ventura 150D</h3>\n          <p class=\"series-desc\">6+ GPH with simple analog controls — feed pressure gauge and product flow meter.</p>\n          <div class=\"series-stats\">\n            <span class=\"ss\"><b>12/24V</b><i>Voltage</i></span>\n            <span class=\"ss\"><b>6+ GPH</b><i>Output</i></span>\n            <span class=\"ss\"><b>60 lbs</b><i>Weight</i></span>\n            <span class=\"ss\"><b>No</b><i>MFD</i></span>\n          </div>\n        </div>\n      </button>\n\n      <button type=\"button\" class=\"series-card\" data-model=\"200C\" aria-pressed=\"false\">\n        <div class=\"series-img\">\n          <img src=\"https://spectrawatermakers.com/cdn/shop/files/IMG_Spectrawatermakers_Ventura_200C.png?v=1742998666&width=900\" alt=\"Ventura 200C\" loading=\"lazy\" />\n        </div>\n        <div class=\"series-body\">\n          <h3>Ventura 200C</h3>\n          <p class=\"series-desc\">8+ GPH for warm water above 50°F. Remote operation and advanced modes via Spectra Connect.</p>\n          <div class=\"series-stats\">\n            <span class=\"ss\"><b>12/24V</b><i>Voltage</i></span>\n            <span class=\"ss\"><b>8+ GPH</b><i>Output</i></span>\n            <span class=\"ss\"><b>85 lbs</b><i>Weight</i></span>\n            <span class=\"ss\"><b>Yes</b><i>MFD</i></span>\n          </div>\n        </div>\n      </button>\n\n      <button type=\"button\" class=\"series-card\" data-model=\"200R-T\" aria-pressed=\"false\">\n        <div class=\"series-img\">\n          <img src=\"https://spectrawatermakers.com/cdn/shop/files/IMG_Spectrawatermakers_Ventura_200R-T.png?v=1742998664&width=900\" alt=\"Ventura 200R-T\" loading=\"lazy\" />\n        </div>\n        <div class=\"series-body\">\n          <h3>Ventura 200R-T</h3>\n          <p class=\"series-desc\">8+ GPH for tropical conditions. Modular design with reliable remote control for tight spaces.</p>\n          <div class=\"series-stats\">\n            <span class=\"ss\"><b>12/24V</b><i>Voltage</i></span>\n            <span class=\"ss\"><b>8+ GPH</b><i>Output</i></span>\n            <span class=\"ss\"><b>85 lbs</b><i>Weight</i></span>\n            <span class=\"ss\"><b>No</b><i>MFD</i></span>\n          </div>\n        </div>\n      </button>\n\n      <button type=\"button\" class=\"series-card\" data-model=\"200T\" aria-pressed=\"false\">\n        <div class=\"series-img\">\n          <img src=\"https://spectrawatermakers.com/cdn/shop/files/IMG_SpectraWatermakers_Ventura_200T.png?v=1742998663&width=900\" alt=\"Ventura 200T\" loading=\"lazy\" />\n        </div>\n        <div class=\"series-body\">\n          <h3>Ventura 200T</h3>\n          <p class=\"series-desc\">8+ GPH for tropical conditions with simple analog controls. Compact, modular, reliable.</p>\n          <div class=\"series-stats\">\n            <span class=\"ss\"><b>12/24V</b><i>Voltage</i></span>\n            <span class=\"ss\"><b>8+ GPH</b><i>Output</i></span>\n            <span class=\"ss\"><b>60 lbs</b><i>Weight</i></span>\n            <span class=\"ss\"><b>No</b><i>MFD</i></span>\n          </div>\n        </div>\n      </button>\n\n    </div>\n\n    <!-- Model overview panel -->\n    <div class=\"series-overview reveal\" id=\"seriesOverview\" aria-live=\"polite\">\n      <div class=\"series-overview-inner\">\n        <div class=\"series-overview-head\">\n          <span class=\"eyebrow\" id=\"ovEyebrow\">Selected model</span>\n          <h3 id=\"ovTitle\">Ventura 150R</h3>\n          <p id=\"ovBlurb\">Spectra's most efficient compact watermaker — built for cruisers and liveaboards who run on solar and a 12V house bank.</p>\n        </div>\n        <div class=\"series-overview-stats\">\n          <div class=\"ov-stat\"><span class=\"ov-lab\">Output</span><span class=\"ov-val\" id=\"ovOutput\">6.3 GPH</span></div>\n          <div class=\"ov-stat\"><span class=\"ov-lab\">Voltage</span><span class=\"ov-val\" id=\"ovVoltage\">12 / 24V DC</span></div>\n          <div class=\"ov-stat\"><span class=\"ov-lab\">Weight</span><span class=\"ov-val\" id=\"ovWeight\">60 lbs</span></div>\n          <div class=\"ov-stat\"><span class=\"ov-lab\">Best for</span><span class=\"ov-val\" id=\"ovBest\">30–45 ft cruisers</span></div>\n        </div>\n        <ul class=\"series-overview-bullets\" id=\"ovBullets\">\n          <li>Energy-recovery Clark Pump architecture — low amp draw</li>\n          <li>Modular install — components mount independently</li>\n          <li>Remote Manual control panel</li>\n          <li>Quiet operation, ideal at anchor</li>\n        </ul>\n      </div>\n    </div>\n\n    <div class=\"series-cta reveal\">\n      <span>Not sure which Ventura is right for your boat? <strong>Contact SeaLife Marine for a sizing recommendation.</strong></span>\n    </div>\n  </div>\n</section>\n\n\n<!-- ============ SPECS ============ -->\n<section class=\"specs\" id=\"specs\">\n  <div class=\"wrap\">\n    <div class=\"section-head reveal\">\n      <div>\n        <div class=\"eyebrow\">Specifications</div>\n        <h2>Built for the realities of life on a battery bank.</h2>\n      </div>\n      <p class=\"subtitle\">The Ventura 150R is engineered for low draw, high recovery, and a footprint that fits real boats. Specifications per Spectra's published VT-150R-12 fact sheet.</p>\n    </div>\n\n    <div class=\"spec-grid reveal\">\n      <div class=\"spec\">\n        <div class=\"label\">Production</div>\n        <div class=\"value\">6.3<span class=\"unit\">GPH</span></div>\n        <div class=\"note\">≈ 24 L/hour fresh water</div>\n      </div>\n      <div class=\"spec\">\n        <div class=\"label\">Voltage</div>\n        <div class=\"value\">12 / 24<span class=\"unit\">V DC</span></div>\n        <div class=\"note\">Direct off house bank</div>\n      </div>\n      <div class=\"spec\">\n        <div class=\"label\">Power Source</div>\n        <div class=\"value\">DC</div>\n        <div class=\"note\">Battery · solar · wind</div>\n      </div>\n      <div class=\"spec\">\n        <div class=\"label\">Weight</div>\n        <div class=\"value\">60<span class=\"unit\">lbs</span></div>\n        <div class=\"note\">27.2 kg total system</div>\n      </div>\n      <div class=\"spec\">\n        <div class=\"label\">Energy Recovery</div>\n        <div class=\"value\">Clark Pump</div>\n        <div class=\"note\">Spectra signature design</div>\n      </div>\n      <div class=\"spec\">\n        <div class=\"label\">Form Factor</div>\n        <div class=\"value\">Modular</div>\n        <div class=\"note\">Compact, fits-anywhere</div>\n      </div>\n      <div class=\"spec\">\n        <div class=\"label\">Control</div>\n        <div class=\"value\">Remote</div>\n        <div class=\"note\">Spectra Remote Manual</div>\n      </div>\n      <div class=\"spec\">\n        <div class=\"label\">Pump</div>\n        <div class=\"value\">Diaphragm</div>\n        <div class=\"note\">Run-dry protection</div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ FEATURES ============ -->\n<section class=\"features\" id=\"features\">\n  <div class=\"wrap\">\n    <div class=\"section-head reveal\">\n      <div>\n        <div class=\"eyebrow\">Why the 150R</div>\n        <h2>Engineered for boats that have to budget every amp.</h2>\n      </div>\n      <p class=\"subtitle\">Spectra's energy-recovery Clark Pump architecture makes potable water with a fraction of the power draw of a conventional high-pressure system — so you can run on solar, off the bank, or under sail.</p>\n    </div>\n\n    <div class=\"feature-grid\">\n      <article class=\"feature reveal\">\n        <div class=\"icon-box\">\n          <svg class=\"ico-svg\" viewBox=\"0 0 24 24\"><path d=\"M13 3 4 14h7l-1 7 9-11h-7l1-7Z\"/></svg>\n        </div>\n        <h3>Clark Pump energy recovery</h3>\n        <p>Spectra's signature pressure intensifier reuses brine-line energy, dropping power demand to a fraction of legacy high-pressure systems at the same output.</p>\n      </article>\n      <article class=\"feature reveal\">\n        <div class=\"icon-box\">\n          <svg class=\"ico-svg\" viewBox=\"0 0 24 24\"><rect x=\"2\" y=\"7\" width=\"18\" height=\"10\" rx=\"2\"/><path d=\"M22 11v2\"/><path d=\"M6 11v2M10 10v4\"/></svg>\n        </div>\n        <h3>Runs straight off DC</h3>\n        <p>No inverter, no genset start-up. Make water on the hook, off solar, or under sail — anywhere the house bank has charge. Available in 12V or 24V configurations.</p>\n      </article>\n      <article class=\"feature reveal\">\n        <div class=\"icon-box\">\n          <svg class=\"ico-svg\" viewBox=\"0 0 24 24\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/></svg>\n        </div>\n        <h3>Modular, fits-anywhere install</h3>\n        <p>Pump, Clark assembly, and membrane housing mount independently — tuck the pieces into lockers, lazarettes, or under bunks. Ideal for retrofits where space is at a premium.</p>\n      </article>\n      <article class=\"feature reveal\">\n        <div class=\"icon-box\">\n          <svg class=\"ico-svg\" viewBox=\"0 0 24 24\"><circle cx=\"12\" cy=\"12\" r=\"9\"/><path d=\"M9 9h6M9 12h6M9 15h4\"/></svg>\n        </div>\n        <h3>Remote control included</h3>\n        <p>Mount the Spectra Remote Manual at the helm or galley. Start, stop, and freshwater-flush with the press of a button. Tank-full indication when used with a tank switch.</p>\n      </article>\n      <article class=\"feature reveal\">\n        <div class=\"icon-box\">\n          <svg class=\"ico-svg\" viewBox=\"0 0 24 24\"><path d=\"M3 12c2 0 3-3 5-3s3 6 5 6 3-6 5-6 3 3 3 3\"/></svg>\n        </div>\n        <h3>Whisper-quiet operation</h3>\n        <p>Commercial-grade diaphragm pumps with run-dry protection replace the high-RPM piston pumps of legacy systems — quiet enough to run overnight without disturbing the v-berth.</p>\n      </article>\n      <article class=\"feature reveal\">\n        <div class=\"icon-box\">\n          <svg class=\"ico-svg\" viewBox=\"0 0 24 24\"><path d=\"M12 3a4 4 0 0 1 4 4v3a4 4 0 0 1-8 0V7a4 4 0 0 1 4-4Z\"/><path d=\"M5 21h14M12 17v4\"/></svg>\n        </div>\n        <h3>Sustainable, off-grid ready</h3>\n        <p>Run your watermaker on solar, wind, or battery. Z±ION compatible for long-term storage. Generate fresh water with minimal environmental impact.</p>\n      </article>\n    </div>\n  </div>\n</section>\n\n<!-- ============ HOW IT WORKS ============ -->\n<section class=\"how\" id=\"how\">\n  <div class=\"wrap\">\n    <div class=\"section-head reveal\">\n      <div>\n        <div class=\"eyebrow\">How it works</div>\n        <h2>Seawater in, drinkable water out — four stages.</h2>\n      </div>\n      <p class=\"subtitle\">A simplified look at the path from seacock to tank. Press a single button on the Remote Manual; the 150R initiates reverse osmosis and automatically diverts product water to your boat's tank when it meets potable spec.</p>\n    </div>\n\n    <div class=\"flow reveal\">\n      <div class=\"flow-step\">\n        <h4>Intake & prefilter</h4>\n        <p>Seawater is drawn through a strainer and 5-micron prefilter, removing silt and debris before it reaches the pump.</p>\n      </div>\n      <div class=\"flow-step\">\n        <h4>Boost pump</h4>\n        <p>A DC diaphragm pump with run-dry protection feeds clean seawater to the Clark Pump at modest pressure — keeping noise and current draw low.</p>\n      </div>\n      <div class=\"flow-step\">\n        <h4>Clark Pump intensifier</h4>\n        <p>Brine-line pressure is recycled to amplify feed pressure — the key to the 150R's exceptional gallons-per-amp efficiency.</p>\n      </div>\n      <div class=\"flow-step\">\n        <h4>RO membrane &amp; auto-divert</h4>\n        <p>The TFC membrane rejects salts and contaminants. Product water is automatically diverted to your tank only when it meets potable specification.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ APPLICATIONS ============ -->\n<section class=\"apps\" id=\"applications\">\n  <div class=\"wrap\">\n    <div class=\"section-head reveal\">\n      <div>\n        <div class=\"eyebrow\">Right-sized for</div>\n        <h2>The boats we install on most.</h2>\n      </div>\n      <p class=\"subtitle\">A 150R is the natural fit for a 2–4 person crew that wants water independence without rewiring the boat. Here's where SeaLife Marine puts them most often.</p>\n    </div>\n\n    <div class=\"app-grid reveal\">\n      <article class=\"app\">\n        <svg class=\"app-icon\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M6 36h36l-3 6H9z\"/><path d=\"M24 6v30M24 6l-9 18M24 6l9 18\"/></svg>\n        <h3>Cruising sailboats</h3>\n        <p>30–45 ft monohulls with solar + DC house bank. Make a day's water during peak charging without firing the engine.</p>\n      </article>\n      <article class=\"app\">\n        <svg class=\"app-icon\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 32h40l-4 8H8z\"/><path d=\"M8 32V20l8-6h16l8 6v12\"/><path d=\"M16 14V8h16v6\"/></svg>\n        <h3>Sportfish &amp; express</h3>\n        <p>Top up tanks and run the rinse-down on multi-day offshore runs. Compact enough for a console or lazarette mount.</p>\n      </article>\n      <article class=\"app\">\n        <svg class=\"app-icon\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 34h40l-4 8H8z\"/><path d=\"M10 34V18M38 34V18\"/><path d=\"M10 18h28\"/><path d=\"M24 18V8\"/></svg>\n        <h3>Catamarans</h3>\n        <p>Modular install spreads weight between hulls and frees up the engine room. A natural pairing with cat solar arrays.</p>\n      </article>\n      <article class=\"app\">\n        <svg class=\"app-icon\" viewBox=\"0 0 48 48\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"24\" cy=\"24\" r=\"18\"/><circle cx=\"24\" cy=\"24\" r=\"6\"/><path d=\"M24 6v6M24 36v6M6 24h6M36 24h6\"/></svg>\n        <h3>Liveaboards &amp; off-grid</h3>\n        <p>Quiet enough to run overnight. Pair with a 400W+ solar array for indefinite water independence at remote anchorages.</p>\n      </article>\n    </div>\n  </div>\n</section>\n\n<!-- ============ FAQ ============ -->\n<section class=\"faq\" id=\"faq\">\n  <div class=\"wrap\">\n    <div class=\"section-head reveal\">\n      <div>\n        <div class=\"eyebrow\">FAQ</div>\n        <h2>Common questions about the Ventura 150R.</h2>\n      </div>\n    </div>\n\n    <div class=\"faq-list reveal\">\n      <details class=\"faq-item\" open>\n        <summary class=\"faq-q\">\n          How long does a typical install take?\n          <span class=\"plus\">+</span>\n        </summary>\n        <div class=\"faq-a\">Most modular installs are completed in 1–2 days, depending on access to the chosen mounting locations and how the through-hulls are configured. We provide a detailed boat-survey before scheduling.</div>\n      </details>\n      <details class=\"faq-item\">\n        <summary class=\"faq-q\">\n          Will the 150R run on solar alone?\n          <span class=\"plus\">+</span>\n        </summary>\n        <div class=\"faq-a\">Yes — the 150R's low DC draw makes it one of the most solar-friendly watermakers on the market. A 400W+ array is generally sufficient to make several hours of water per day in good conditions while still topping the bank.</div>\n      </details>\n      <details class=\"faq-item\">\n        <summary class=\"faq-q\">\n          What maintenance does it actually need?\n          <span class=\"plus\">+</span>\n        </summary>\n        <div class=\"faq-a\">Routine: prefilter swap on a regular interval, freshwater flush after each use, pickling for long lay-ups (Z±ION compatible). Membrane life is typically 5+ years with proper care. We provide a maintenance schedule with every install.</div>\n      </details>\n      <details class=\"faq-item\">\n        <summary class=\"faq-q\">\n          Can I run it dockside?\n          <span class=\"plus\">+</span>\n        </summary>\n        <div class=\"faq-a\">It can run dockside for testing, but watermakers should not be used in marina water for production due to chlorine and contamination. Run it on clean offshore water for production, and flush with dock water through a carbon filter.</div>\n      </details>\n      <details class=\"faq-item\">\n        <summary class=\"faq-q\">\n          Do you handle warranty service?\n          <span class=\"plus\">+</span>\n        </summary>\n        <div class=\"faq-a\">Yes. SeaLife Marine is an authorized Spectra Watermakers dealer and carries out warranty diagnostics, parts replacement, and Spectra-approved service in-house at our Bradenton, FL facility.</div>\n      </details>\n      <details class=\"faq-item\">\n        <summary class=\"faq-q\">\n          Do you service the Tampa Bay area only?\n          <span class=\"plus\">+</span>\n        </summary>\n        <div class=\"faq-a\">Tampa Bay and the Sun Coast are our home waters, but we service the broader Florida west coast on demand and offer yacht-delivery support along the Gulf and Atlantic. Reach out — we likely cover where you are.</div>\n      </details>\n    </div>\n  </div>\n</section>\n\n<!-- ============ CTA / FORM (removed) ============ -->\n\n\n\n\n\n\n\n";
